"""
This module contains the Board class to represent the game board.
"""

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for row in range(3):
            for col in range(0, 8, 2):
                self.board[row][col] = Piece("red", "normal")
        for row in range(5, 8):
            for col in range(1, 9, 2):
                self.board[row][col] = Piece("black", "normal")

    def print_board(self):
        for row in self.board:
            for piece in row:
                if piece is None:
                    print(".", end=" ")
                else:
                    print(piece.symbol(), end=" ")
            print()

class Piece:
    def __init__(self, color, type_="normal"):
        self.color = color
        self.type = type_

    def symbol(self):
        if self.color == "red":
            return "r" if self.type == "normal" else "R"
        else:
            return "b" if self.type == "normal" else "B"

